namespace CodeXCore.ServiceTree
{
    using System;
    using System.Collections.Generic;
    using System.Linq;
    using System.Threading;
    using System.Threading.Tasks;
    using CodeXCore.Services;
    using Microsoft.Extensions.Logging;

    /// <summary>
    /// Resolves Papyrus QuotaAppId values to their owning Product (Org) name
    /// by fetching service auth quotas and resolving their Service Tree parents.
    /// </summary>
    public sealed class AppIdToProductResolver : IAppIdToProductResolver
    {
        private readonly IPapyrusConfigService configService;
        private readonly IServiceTreeParentResolver parentResolver;
        private readonly ILogger<AppIdToProductResolver> logger;

        /// <summary>
        /// Initializes a new instance of the <see cref="AppIdToProductResolver"/> class.
        /// </summary>
        /// <param name="configService">Papyrus config service for fetching service auth quotas.</param>
        /// <param name="parentResolver">Service Tree parent resolver.</param>
        /// <param name="logger">Logger.</param>
        public AppIdToProductResolver(
            IPapyrusConfigService configService,
            IServiceTreeParentResolver parentResolver,
            ILogger<AppIdToProductResolver> logger)
        {
            this.configService = configService ?? throw new ArgumentNullException(nameof(configService));
            this.parentResolver = parentResolver ?? throw new ArgumentNullException(nameof(parentResolver));
            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
        }

        /// <inheritdoc/>
        public async Task<IReadOnlyDictionary<string, string>> ResolveAsync(CancellationToken cancellationToken)
        {
            var result = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

            try
            {
                // 1. Fetch all service auth quota entries.
                var serviceAuthQuotas = await this.configService
                    .GetServiceQuotaAndAuthManagementAsync(string.Empty);

                if (serviceAuthQuotas == null || serviceAuthQuotas.Count == 0)
                {
                    this.logger.LogWarning("AppIdToProductResolver: No service auth quotas found.");
                    return result;
                }

                // 2. Resolve their ServiceTreeIds to parent groups.
                var serviceTreeIds = serviceAuthQuotas
                    .Select(q => q.ServiceTreeId ?? string.Empty)
                    .Where(id => !string.IsNullOrWhiteSpace(id))
                    .Distinct(StringComparer.OrdinalIgnoreCase);

                var parentLookup = await this.parentResolver
                    .ResolveParentsAsync(serviceTreeIds, cancellationToken);

                // 3. Build QuotaAppId → Product mapping.
                foreach (var entry in serviceAuthQuotas)
                {
                    if (string.IsNullOrEmpty(entry.QuotaAppId))
                    {
                        continue;
                    }

                    if (parentLookup.TryGetValue(entry.ServiceTreeId ?? string.Empty, out var parent)
                        && !string.IsNullOrEmpty(parent.Product))
                    {
                        result.TryAdd(entry.QuotaAppId, parent.Product);
                    }
                }

                this.logger.LogInformation(
                    "AppIdToProductResolver resolved {Count} AppId→Product mappings from {TotalCount} service auth quotas.",
                    result.Count,
                    serviceAuthQuotas.Count);
            }
            catch (Exception ex)
            {
                this.logger.LogError(ex, "AppIdToProductResolver failed to resolve AppId→Product mappings.");
            }

            return result;
        }
    }
}

