        /// <summary>
        /// Gets or sets the AAD client secret for app auth.
        /// </summary>
        public string AadClientSecret { get; set; } = string.Empty;

        /// <summary>
        /// Gets or sets the Base64-encoded AAD client certificate (PFX).
        /// </summary>
        public string AadClientCertificateBase64 { get; set; } = string.Empty;

        /// <summary>
        /// Gets or sets the password for the Base64-encoded AAD client certificate.
        /// </summary>
        public string AadClientCertificatePassword { get; set; } = string.Empty;

