        /// </summary>
        public string AadScope { get; set; } = string.Empty;

        /// <summary>
        /// Builds options from environment variables.
        /// </summary>
        /// <returns>Options resolved from environment variables.</returns>
        public static ServiceTreeClientOptions FromEnvironment()
        {
            var options = new ServiceTreeClientOptions();

            bool endpointSet = false;
            string? endpoint = Environment.GetEnvironmentVariable("SERVICETREE_ENDPOINT");
            if (!string.IsNullOrWhiteSpace(endpoint))
            {
                options.Endpoint = endpoint.Trim();
                endpointSet = true;
            }

            string? authMode = Environment.GetEnvironmentVariable("SERVICETREE_AUTH_MODE");
            if (!string.IsNullOrWhiteSpace(authMode)
                && Enum.TryParse(authMode, true, out ServiceTreeAuthenticationMode parsedMode))
            {
                options.AuthenticationMode = parsedMode;
            }

            string? thumbprint = Environment.GetEnvironmentVariable("SERVICETREE_CERT_THUMBPRINT");
            if (!string.IsNullOrWhiteSpace(thumbprint))
            {
                options.CertificateThumbprint = thumbprint.Trim();
            }

            string? storeName = Environment.GetEnvironmentVariable("SERVICETREE_CERT_STORE_NAME");
            if (!string.IsNullOrWhiteSpace(storeName) && Enum.TryParse(storeName, true, out StoreName parsedStoreName))
            {
                options.CertificateStoreName = parsedStoreName;
            }

            string? storeLocation = Environment.GetEnvironmentVariable("SERVICETREE_CERT_STORE_LOCATION");
            if (!string.IsNullOrWhiteSpace(storeLocation) && Enum.TryParse(storeLocation, true, out StoreLocation parsedStoreLocation))
            {
                options.CertificateStoreLocation = parsedStoreLocation;
            }

            string? certBase64 = Environment.GetEnvironmentVariable("SERVICETREE_CERT_BASE64");
            if (!string.IsNullOrWhiteSpace(certBase64))
            {
                options.CertificateBase64 = certBase64.Trim();
            }

            string? certPassword = Environment.GetEnvironmentVariable("SERVICETREE_CERT_PASSWORD");
            if (!string.IsNullOrWhiteSpace(certPassword))
            {
                options.CertificatePassword = certPassword;
            }

            string? aadTenantId = Environment.GetEnvironmentVariable("SERVICETREE_AAD_TENANT_ID");
            if (!string.IsNullOrWhiteSpace(aadTenantId))
            {
                options.AadTenantId = aadTenantId.Trim();
            }

            string? aadClientId = Environment.GetEnvironmentVariable("SERVICETREE_AAD_CLIENT_ID");
            if (!string.IsNullOrWhiteSpace(aadClientId))
            {
                options.AadClientId = aadClientId.Trim();
            }

            string? aadClientSecret = Environment.GetEnvironmentVariable("SERVICETREE_AAD_CLIENT_SECRET");
            if (!string.IsNullOrWhiteSpace(aadClientSecret))
            {
                options.AadClientSecret = aadClientSecret;
            }

            string? aadCertBase64 = Environment.GetEnvironmentVariable("SERVICETREE_AAD_CERT_BASE64");
            if (!string.IsNullOrWhiteSpace(aadCertBase64))
            {
                options.AadClientCertificateBase64 = aadCertBase64.Trim();
            }

            string? aadCertPassword = Environment.GetEnvironmentVariable("SERVICETREE_AAD_CERT_PASSWORD");
            if (!string.IsNullOrWhiteSpace(aadCertPassword))
            {
                options.AadClientCertificatePassword = aadCertPassword;
            }

            string? aadAudience = Environment.GetEnvironmentVariable("SERVICETREE_AAD_AUDIENCE");
            if (!string.IsNullOrWhiteSpace(aadAudience))
            {
                options.AadAudience = aadAudience.Trim();
            }

            string? aadScope = Environment.GetEnvironmentVariable("SERVICETREE_AAD_SCOPE");
            if (!string.IsNullOrWhiteSpace(aadScope))
            {
                options.AadScope = aadScope.Trim();
            }

            if (!endpointSet && (options.AuthenticationMode == ServiceTreeAuthenticationMode.Aad
                || options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential))
            {
                options.Endpoint = DefaultAadEndpoint;
            }

            return options;
        }
    }
